import type { RecommendationInput, RecommendationResult, ScoredProduct, ChatMessage, MatchStatus } from "@/lib/types/canonical"
import type { ProductIntakeForm, AnswerState, MachiningIntent } from "@/lib/types/intake"
import type { ExplorationSessionState, AppliedFilter, NarrowingTurn, NarrowingStage, CandidateSnapshot } from "@/lib/types/exploration"
import type { EvidenceSummary } from "@/lib/types/evidence"
import type { FactCheckedRecommendation } from "@/lib/types/fact-check"
import type { RecommendationExplanation } from "@/lib/types/explanation"

export const maxDuration = 60

// ── POST Handler ─────────────────────────────────────────────
export async function POST(req: Request) {
  try {
    const body = await req.json()

    // Route: intake-based exploration flow
    if (body.intakeForm) {
      return handleExploration(
        body.intakeForm as ProductIntakeForm,
        body.messages ?? [],
        body.sessionState ?? null,
        body.displayedProducts ?? null,
        body.language === "en" ? "en" : "ko"
      )
    }

    // Route: simple chat (legacy, kept for backward compat)
    return handleSimpleChat(body.messages ?? [], body.mode ?? "simple")

  } catch (err) {
    console.error("[recommend] TOP-LEVEL Error:", err)
    const errMsg = err instanceof Error ? err.message : "Unknown error"
    const errStack = err instanceof Error ? err.stack?.split("\n").slice(0, 8).join(" | ") : ""
    return NextResponse.json({
      error: "internal_error",
      detail: errMsg,
      debugStack: errStack,
      text: `오류가 발생했습니다: ${errMsg}`,
      chips: ["처음부터 다시", "소재 입력", "직경 입력"],
      isComplete: false,
      recommendation: null,
      sessionState: null,
      evidenceSummaries: null,
      candidateSnapshot: null,
    }, { status: 500 })
  }
}

// ════════════════════════════════════════════════════════════════
// EXPLORATION HANDLER (session-aware hybrid retrieval + narrowing)
// ════════════════════════════════════════════════════════════════

interface DisplayedProduct {
  rank: number
  code: string
  brand: string | null
  series: string | null
  diameter: number | null
  flute: number | null
  coating: string | null
  materialTags: string[]
  score: number
  matchStatus: string
}

async function handleExploration(
  form: ProductIntakeForm,
  messages: ChatMessage[],
  prevState: ExplorationSessionState | null,
  displayedProducts: DisplayedProduct[] | null = null,
  language: AppLanguage = "ko"
): Promise<Response> {
  console.log(
    `[recommend] request start hasPrevState=${!!prevState} messages=${messages.length} displayedProducts=${displayedProducts?.length ?? 0}`
  )
  const provider = getProvider()
  const baseInput = mapIntakeToInput(form)

  // ── Step 0: Request Preparation ────────────────────────────
  const filters: AppliedFilter[] = prevState?.appliedFilters ?? []
  const resolvedInput: RecommendationInput = prevState?.resolvedInput
    ? { ...baseInput, ...prevState.resolvedInput }
    : baseInput

  let hybridResult: Awaited<ReturnType<typeof runHybridRetrieval>>
  try {
    hybridResult = await runHybridRetrieval(resolvedInput, filters)
  } catch (retrievalError) {
    console.error(`[recommend] runHybridRetrieval FAILED:`, retrievalError)
    // Try without unitSystem/region filters
    const fallbackInput = { ...resolvedInput, unitSystem: undefined, region: undefined }
    try {
      hybridResult = await runHybridRetrieval(fallbackInput, filters)
      console.log(`[recommend] Fallback retrieval succeeded (without unitSystem/region)`)
    } catch (fallbackError) {
      console.error(`[recommend] Fallback retrieval also failed:`, fallbackError)
      const errMsg = retrievalError instanceof Error ? retrievalError.message : "DB 검색 실패"
      return NextResponse.json({
        error: "retrieval_error",
        detail: errMsg,
        text: `DB 검색 중 오류: ${errMsg}`,
        chips: ["처음부터 다시"],
        isComplete: false,
        recommendation: null,
        sessionState: prevState,
        evidenceSummaries: null,
        candidateSnapshot: null,
      }, { status: 500 })
    }
  }
  const candidates = hybridResult.candidates
  const evidenceMap = hybridResult.evidenceMap

  // Run request preparation engine
  const requestPrep = prepareRequest(form, messages, prevState, resolvedInput, candidates.length)
  console.log(`[recommend] Intent: ${requestPrep.intent} (${requestPrep.intentConfidence}), Route: ${requestPrep.route.action}`)

  // Handle reset
  if (requestPrep.route.action === "reset_session") {
    return NextResponse.json({
      text: "처음부터 다시 시작합니다. 새로운 조건을 입력해주세요.",
      purpose: "greeting",
      chips: ["처음부터 다시"],
      isComplete: true,
      recommendation: null,
      sessionState: null,
      evidenceSummaries: null,
      candidateSnapshot: null,
      extractedField: null,
      requestPreparation: requestPrep,
    })
  }

  // NOTE: Pre-orchestrator undo path removed — all undo is handled by orchestrator + session-manager.

  // ── Step 2: Process user message via Orchestrator ───────────
  const narrowingHistory: NarrowingTurn[] = prevState?.narrowingHistory ?? []
  let currentInput = { ...resolvedInput }
  let turnCount = prevState?.turnCount ?? 0

  if (messages.length > 0 && prevState) {
    const lastUserMsg = [...messages].reverse().find(m => m.role === "user")
    if (lastUserMsg) {
      // ═══ Multi-Agent Orchestration ═══
      const turnCtx: TurnContext = {
        userMessage: lastUserMsg.text,
        intakeForm: form,
        sessionState: prevState,
        resolvedInput: currentInput,
        candidateCount: candidates.length,
        displayedProducts: buildCandidateSnapshot(candidates, evidenceMap),
        currentCandidates: candidates,
      }

      let orchResult: OrchestratorResult
      console.log(`[recommend] Step 2: orchestrator start | msg="${lastUserMsg.text.slice(0, 50)}" | candidates=${candidates.length} | lastAction=${prevState.lastAction} | lastField=${prevState.lastAskedField}`)
      try {
        if (ENABLE_TOOL_USE_ROUTING) {
          try {
            const toolStart = Date.now()
            orchResult = await orchestrateTurnWithTools(turnCtx, provider)
            console.log(`[recommend] Tool-use succeeded in ${Date.now() - toolStart}ms | action=${orchResult.action.type}`)
          } catch (toolUseError) {
            console.warn(`[recommend] Tool-use routing failed (${toolUseError instanceof Error ? toolUseError.message : toolUseError}), falling back to legacy`)
            orchResult = await orchestrateTurn(turnCtx, provider)
          }
        } else {
          orchResult = await orchestrateTurn(turnCtx, provider)
        }
      } catch (orchError) {
        console.error(`[recommend] All orchestration failed:`, orchError)
        // Smart fallback: try to parse chip selection directly
        const chipClean = lastUserMsg.text.replace(/\s*\(\d+개\)\s*$/, "").replace(/\s*—\s*.+$/, "").trim()
        const lastField = prevState.lastAskedField
        if (lastField && chipClean) {
          const directFilter = parseAnswerToFilter(lastField, chipClean)
          if (directFilter) {
            console.log(`[recommend] Fallback: direct chip parse → ${lastField}=${chipClean}`)
            orchResult = {
              action: { type: "continue_narrowing", filter: { ...directFilter, appliedAt: turnCount } },
              reasoning: "orchestration_error:direct_chip_fallback",
              agentsInvoked: [],
              escalatedToOpus: false,
            }
          } else {
            orchResult = {
              action: { type: "answer_general", message: `현재 ${candidates.length}개 후보가 있습니다. 질문을 다시 말씀해주세요.`, preGenerated: true },
              reasoning: "orchestration_error:fallback",
              agentsInvoked: [],
              escalatedToOpus: false,
            }
          }
        } else {
          orchResult = {
            action: { type: "answer_general", message: `현재 ${candidates.length}개 후보가 있습니다. 질문을 다시 말씀해주세요.`, preGenerated: true },
            reasoning: "orchestration_error:fallback",
            agentsInvoked: [],
            escalatedToOpus: false,
          }
        }
      }
      let action = orchResult.action

      // ── Guard: apply_filter in post-recommendation state → redirect ALL to filter_displayed ──
      const POST_RECOMMENDATION_ACTIONS = new Set(["show_recommendation", "filter_displayed", "query_displayed"])
      if (action.type === "continue_narrowing" && POST_RECOMMENDATION_ACTIONS.has(prevState.lastAction ?? "")) {
        const filterField = action.filter.field
        const normalized = normalizeFieldName(filterField) ?? filterField
        console.log(`[orchestrator:guard] apply_filter(${filterField}) redirected to filter_displayed in post-recommendation state`)
        action = {
          type: "filter_displayed",
          field: normalized,
          operator: action.filter.op === "eq" ? "eq" : action.filter.op === "includes" ? "contains" : action.filter.op,
          value: String(action.filter.rawValue),
        }
        orchResult = { ...orchResult, action }
      }

      // ── Dispatch orchestrator action ──────────────────────

      // Action: reset_session
      if (action.type === "reset_session") {
        return NextResponse.json({
          text: "처음부터 다시 시작합니다. 새로운 조건을 입력해주세요.",
          purpose: "greeting",
          chips: ["처음부터 다시"],
          isComplete: true,
          recommendation: null,
          sessionState: null,
          evidenceSummaries: null,
          candidateSnapshot: null,
          extractedField: null,
          requestPreparation: requestPrep,
        })
      }

      // Action: go_back_one_step / go_back_to_filter — delegated to session-manager
      if (action.type === "go_back_one_step" || action.type === "go_back_to_filter") {
        const restoreResult = action.type === "go_back_to_filter"
          ? restoreToBeforeFilter(prevState, action.filterValue ?? "", action.filterField, baseInput, applyFilterToInput)
          : restoreOnePreviousStep(prevState, baseInput, applyFilterToInput)

        const undoResult = await runHybridRetrieval(restoreResult.rebuiltInput, restoreResult.remainingFilters.filter(f => f.op !== "skip"))

        console.log(`[session-manager:undo] Reverted "${restoreResult.removedFilterDesc}": ${prevState.candidateCount} → ${undoResult.candidates.length} candidates, filters: ${prevState.appliedFilters.length} → ${restoreResult.remainingFilters.length}`)

        return buildQuestionResponse(
          form, undoResult.candidates, undoResult.evidenceMap, restoreResult.rebuiltInput,
          restoreResult.remainingHistory, restoreResult.remainingFilters, restoreResult.undoTurnCount,
          messages, provider, language, undefined, restoreResult.remainingStages
        )
      }

      // Action: show_recommendation
      if (action.type === "show_recommendation") {
        // If in-display filter is active, recommend only from filtered set
        if (prevState.displayedSetFilter && prevState.displayedCandidates?.length > 0) {
          const filteredCodes = new Set(prevState.displayedCandidates.map(c => c.productCode))
          const filteredCandidates = candidates.filter(c => filteredCodes.has(c.product.normalizedCode))

          if (filteredCandidates.length > 0) {
            console.log(`[recommend] show_recommendation with in-display filter: ${candidates.length} → ${filteredCandidates.length} candidates`)
            return buildRecommendationResponse(
              form, filteredCandidates, evidenceMap, currentInput, narrowingHistory,
              filters, turnCount, messages, provider, language, displayedProducts
            )
          }
        }

        return buildRecommendationResponse(
          form, candidates, evidenceMap, currentInput, narrowingHistory,
          filters, turnCount, messages, provider, language, displayedProducts
        )
      }

      // Action: replace_slot — remove old filter value, apply new value
      if (action.type === "replace_slot") {
        const field = action.field
        const existingIdx = filters.findIndex(f => f.field === field && f.op !== "skip")

        // Save old filter before removing (needed for zero-candidate revert)
        let oldValue = "(없음)"
        let savedOldFilter: AppliedFilter | null = null
        if (existingIdx >= 0) {
          oldValue = filters[existingIdx].value
          savedOldFilter = { ...filters[existingIdx] }
          filters.splice(existingIdx, 1)
        }

        // Build new filter
        const isNumeric = !isNaN(Number(action.newValue))
        const newFilter: AppliedFilter = {
          field,
          op: isNumeric ? "eq" : "includes",
          value: action.displayValue ?? action.newValue,
          rawValue: isNumeric ? Number(action.newValue) : action.newValue,
          appliedAt: turnCount,
        }
        filters.push(newFilter)

        // Rebuild input from base + all filters
        let rebuiltInput = { ...baseInput }
        for (const f of filters) {
          rebuiltInput = applyFilterToInput(rebuiltInput, f)
        }
        currentInput = rebuiltInput

        // Re-run retrieval
        const newResult = await runHybridRetrieval(currentInput, filters.filter(f => f.op !== "skip"))

        // ── Zero-candidate guard: if new value results in 0 candidates, revert ──
        if (newResult.candidates.length === 0) {
          // Revert: remove new filter, restore old filter
          filters.pop()
          if (existingIdx >= 0 && savedOldFilter) {
            filters.push(savedOldFilter)
          }
          // Rebuild input from base + all filters
          let revertInput = { ...baseInput }
          for (const f of filters) {
            revertInput = applyFilterToInput(revertInput, f)
          }
          currentInput = revertInput

          console.log(`[orchestrator:guard] replace_slot ${field}=${action.newValue} would result in 0 candidates — BLOCKED`)
          return buildQuestionResponse(
            form, candidates, evidenceMap, currentInput,
            narrowingHistory, filters, turnCount, messages, provider, language,
            `"${action.displayValue ?? action.newValue}" 조건을 적용하면 후보가 없습니다. 현재 ${candidates.length}개 후보에서 다른 값을 선택해주세요.`
          )
        }

        narrowingHistory.push({
          question: "slot-replace",
          answer: `${field}: ${oldValue} → ${action.displayValue ?? action.newValue}`,
          extractedFilters: [newFilter],
          candidateCountBefore: candidates.length,
          candidateCountAfter: newResult.candidates.length,
        })
        turnCount++

        console.log(`[orchestrator:slot-replace] ${field}: ${oldValue} → ${action.newValue} | ${candidates.length} → ${newResult.candidates.length} candidates`)

        const replaceText = `${field}를 ${oldValue}에서 **${action.displayValue ?? action.newValue}**로 변경했습니다.\n후보가 ${newResult.candidates.length}개로 업데이트되었습니다.`

        const status = checkResolution(newResult.candidates, narrowingHistory)
        if (status.startsWith("resolved")) {
          return buildRecommendationResponse(
            form, newResult.candidates, newResult.evidenceMap, currentInput,
            narrowingHistory, filters, turnCount, messages, provider, language, displayedProducts
          )
        }

        return buildQuestionResponse(
          form, newResult.candidates, newResult.evidenceMap, currentInput,
          narrowingHistory, filters, turnCount, messages, provider, language, replaceText
        )
      }

      // Action: ask_clarification — present options to user
      if (action.type === "ask_clarification") {
        const clarifyChips = [...action.options]
        if (action.allowDirectInput) clarifyChips.push("직접 입력")

        const sessionState: ExplorationSessionState = {
          sessionId: prevState.sessionId ?? `ses-${Date.now()}`,
          candidateCount: prevState.candidateCount ?? candidates.length,
          appliedFilters: filters,
          narrowingHistory,
          stageHistory: prevState.stageHistory ?? [],
          resolutionStatus: prevState.resolutionStatus ?? "broad",
          resolvedInput: currentInput,
          turnCount,
          lastAskedField: prevState.lastAskedField,
          displayedCandidates: prevState.displayedCandidates ?? [],
          fullDisplayedCandidates: prevState.fullDisplayedCandidates,
          displayedSetFilter: prevState.displayedSetFilter,
          displayedChips: clarifyChips,
          displayedOptions: prevState.displayedOptions ?? [],
          lastAction: "ask_clarification",
        }
        return NextResponse.json({
          text: action.question,
          purpose: "question",
          chips: clarifyChips,
          isComplete: false,
          recommendation: null,
          sessionState,
          evidenceSummaries: null,
          candidateSnapshot: prevState.displayedCandidates ?? null,
          extractedField: null, requestPreparation: null,
          primaryExplanation: null, primaryFactChecked: null,
          altExplanations: [], altFactChecked: [],
          orchestratorResult: { action: action.type, agents: orchResult.agentsInvoked, opus: orchResult.escalatedToOpus },
        })
      }

      // Action: compare_products — use PERSISTED displayed candidates (not re-computed)
      if (action.type === "compare_products") {
        const snapshot = prevState.displayedCandidates?.length > 0
          ? prevState.displayedCandidates
          : buildCandidateSnapshot(candidates, evidenceMap)
        const targets = resolveProductReferences(action.targets, snapshot)
        const compResult = await compareProducts(targets, evidenceMap, provider)

        const sessionState: ExplorationSessionState = {
          sessionId: prevState.sessionId ?? `ses-${Date.now()}`,
          candidateCount: candidates.length,
          appliedFilters: filters,
          narrowingHistory,
          stageHistory: prevState.stageHistory ?? [],
          resolutionStatus: prevState.resolutionStatus ?? "broad",
          resolvedInput: currentInput,
          turnCount,
          displayedCandidates: snapshot,
          fullDisplayedCandidates: prevState.fullDisplayedCandidates,
          displayedSetFilter: prevState.displayedSetFilter ?? null,
          displayedChips: ["추천해주세요", "다른 조건으로", "⟵ 이전 단계", "처음부터 다시"],
          displayedOptions: [],
          lastAction: "compare_products",
        }
        return NextResponse.json({
          text: compResult.text,
          purpose: "comparison",
          chips: ["추천해주세요", "다른 조건으로", "⟵ 이전 단계", "처음부터 다시"],
          isComplete: false,
          recommendation: null,
          sessionState,
          evidenceSummaries: null,
          candidateSnapshot: snapshot,
          extractedField: null,
          requestPreparation: null,
          primaryExplanation: null,
          primaryFactChecked: null,
          altExplanations: [],
          altFactChecked: [],
          orchestratorResult: { action: action.type, agents: orchResult.agentsInvoked, opus: orchResult.escalatedToOpus },
        })
      }

      // Action: explain_product / answer_general
      if (action.type === "explain_product" || action.type === "answer_general") {
        const inventoryReply = await handleDirectInventoryQuestion(
          lastUserMsg.text,
          prevState
        )
        if (inventoryReply) {
          const sessionState: ExplorationSessionState = {
            sessionId: prevState.sessionId ?? `ses-${Date.now()}`,
            candidateCount: prevState.candidateCount ?? candidates.length,
            appliedFilters: filters,
            narrowingHistory,
            stageHistory: prevState.stageHistory ?? [],
            resolutionStatus: prevState.resolutionStatus ?? "broad",
            resolvedInput: currentInput,
            turnCount,
            lastAskedField: prevState.lastAskedField,
            displayedCandidates: prevState.displayedCandidates ?? [],
            displayedChips: inventoryReply.chips,
            displayedOptions: prevState.displayedOptions ?? [],
            lastAction: "answer_general",
          }
          return NextResponse.json({
            text: inventoryReply.text,
            purpose: "general_chat",
            chips: inventoryReply.chips,
            isComplete: false,
            recommendation: null,
            sessionState,
            evidenceSummaries: null,
            candidateSnapshot: prevState.displayedCandidates ?? null,
            extractedField: null, requestPreparation: null,
            primaryExplanation: null, primaryFactChecked: null,
            altExplanations: [], altFactChecked: [],
            orchestratorResult: { action: action.type, agents: orchResult.agentsInvoked, opus: orchResult.escalatedToOpus },
          })
        }

        const cuttingConditionReply = await handleDirectCuttingConditionQuestion(
          lastUserMsg.text,
          currentInput,
          prevState
        )
        if (cuttingConditionReply) {
          const sessionState: ExplorationSessionState = {
            sessionId: prevState.sessionId ?? `ses-${Date.now()}`,
            candidateCount: prevState.candidateCount ?? candidates.length,
            appliedFilters: filters,
            narrowingHistory,
            stageHistory: prevState.stageHistory ?? [],
            resolutionStatus: prevState.resolutionStatus ?? "broad",
            resolvedInput: currentInput,
            turnCount,
            lastAskedField: prevState.lastAskedField,
            displayedCandidates: prevState.displayedCandidates ?? [],
            fullDisplayedCandidates: prevState.fullDisplayedCandidates,
            displayedSetFilter: prevState.displayedSetFilter ?? null,
            displayedChips: cuttingConditionReply.chips,
            displayedOptions: prevState.displayedOptions ?? [],
            lastAction: "answer_general",
          }
          return NextResponse.json({
            text: cuttingConditionReply.text,
            purpose: "general_chat",
            chips: cuttingConditionReply.chips,
            isComplete: false,
            recommendation: null,
            sessionState,
            evidenceSummaries: null,
            candidateSnapshot: prevState.displayedCandidates ?? null,
            extractedField: null, requestPreparation: null,
            primaryExplanation: null, primaryFactChecked: null,
            altExplanations: [], altFactChecked: [],
            orchestratorResult: { action: action.type, agents: orchResult.agentsInvoked, opus: orchResult.escalatedToOpus },
          })
        }

        // Resolve targets from displayed products
        const explainSnapshot = prevState.displayedCandidates?.length > 0
          ? prevState.displayedCandidates
          : buildCandidateSnapshot(candidates, evidenceMap)
        const explainTargets = action.type === "explain_product" && action.target ? [action.target] : []
        const resolved = resolveProductReferences(explainTargets, explainSnapshot)
        const productLines = resolved.map(p =>
          `**#${p.rank} ${p.displayCode}**${p.displayLabel ? ` [${p.displayLabel}]` : ""}\n` +
          `${p.brand ?? "?"} | ${p.seriesName ?? "?"}\n` +
          `φ${p.diameterMm ?? "?"}mm · ${p.fluteCount ?? "?"}날 · ${p.coating ?? "?"} · ${p.toolMaterial ?? "?"}\n` +
          `Shank ${p.shankDiameterMm ?? "?"}mm · CL ${p.lengthOfCutMm ?? "?"}mm · OAL ${p.overallLengthMm ?? "?"}mm\n` +
          `매칭: ${p.matchStatus} (${p.score}점) | 재고: ${p.stockStatus}`
        ).join("\n\n")

        const responseText = `요청하신 제품 ${resolved.length}개입니다:\n\n${productLines}`

        const sessionState: ExplorationSessionState = {
          sessionId: prevState.sessionId ?? `ses-${Date.now()}`,
          candidateCount: prevState.candidateCount,
          appliedFilters: filters,
          narrowingHistory,
          stageHistory: prevState.stageHistory ?? [],
          resolutionStatus: prevState.resolutionStatus ?? "broad",
          resolvedInput: currentInput,
          turnCount,
          lastAskedField: prevState.lastAskedField,
          displayedCandidates: explainSnapshot,
          fullDisplayedCandidates: prevState.fullDisplayedCandidates,
          displayedSetFilter: prevState.displayedSetFilter ?? null,
          displayedChips: ["비교해줘", "추천해주세요", "⟵ 이전 단계"],
          displayedOptions: prevState.displayedOptions ?? [],
          lastAction: "answer_general",
        }
        return NextResponse.json({
          text: responseText,
          purpose: "recommendation",
          chips: ["비교해줘", "추천해주세요", "⟵ 이전 단계"],
          isComplete: false,
          recommendation: null,
          sessionState,
          evidenceSummaries: null,
          candidateSnapshot: resolved.length > 0 ? resolved : explainSnapshot,
          extractedField: null, requestPreparation: null,
          primaryExplanation: null, primaryFactChecked: null,
          altExplanations: [], altFactChecked: [],
          orchestratorResult: { action: action.type, agents: orchResult.agentsInvoked, opus: orchResult.escalatedToOpus },
        })
      }

      // Action: filter_displayed — in-display 필터링
      if (action.type === "filter_displayed") {
        const snapshot = prevState.displayedCandidates?.length > 0
          ? prevState.displayedCandidates
          : buildCandidateSnapshot(candidates, evidenceMap)

        // Reset filter → restore fullDisplayedCandidates
        if (action.field === "reset" || action.operator === "reset") {
          const restored = prevState.fullDisplayedCandidates?.length
            ? prevState.fullDisplayedCandidates
            : snapshot
          const sessionState: ExplorationSessionState = {
            sessionId: prevState.sessionId ?? `ses-${Date.now()}`,
            candidateCount: prevState.candidateCount ?? candidates.length,
            appliedFilters: filters,
            narrowingHistory,
            stageHistory: prevState.stageHistory ?? [],
            resolutionStatus: prevState.resolutionStatus ?? "broad",
            resolvedInput: currentInput,
            turnCount,
            lastAskedField: prevState.lastAskedField,
            displayedCandidates: restored,
            fullDisplayedCandidates: prevState.fullDisplayedCandidates,
            displayedSetFilter: null,
            displayedChips: prevState.displayedChips ?? [],
            displayedOptions: prevState.displayedOptions ?? [],
            lastAction: "filter_displayed",
          }
          return NextResponse.json({
            text: `전체 ${restored.length}개 제품을 다시 표시합니다.`,
            purpose: "question",
            chips: prevState.displayedChips ?? ["추천해주세요", "처음부터 다시"],
            isComplete: false,
            recommendation: null,
            sessionState,
            evidenceSummaries: null,
            candidateSnapshot: restored,
            extractedField: null, requestPreparation: null,
            primaryExplanation: null, primaryFactChecked: null,
            altExplanations: [], altFactChecked: [],
            orchestratorResult: { action: action.type, agents: orchResult.agentsInvoked, opus: orchResult.escalatedToOpus },
          })
        }

        // Save full list (first time only)
        const fullList = prevState.fullDisplayedCandidates?.length
          ? prevState.fullDisplayedCandidates
          : snapshot

        // Apply filter or keep_indices
        let filtered: CandidateSnapshot[]
        if (action.keepIndices?.length) {
          filtered = snapshot.filter(c => action.keepIndices!.includes(c.rank))
        } else if (action.field === "materialTags") {
          // Special handling for array fields (materialTags)
          filtered = snapshot.filter(c => {
            const tags = c.materialTags ?? []
            const targetStr = action.value.toLowerCase()
            switch (action.operator) {
              case "contains": return tags.some(t => t.toLowerCase().includes(targetStr))
              case "eq": return tags.some(t => t.toLowerCase() === targetStr)
              case "neq": return !tags.some(t => t.toLowerCase() === targetStr)
              default: return tags.some(t => t.toLowerCase() === targetStr)
            }
          })
        } else {
          filtered = snapshot.filter(c => {
            const fieldVal = (c as unknown as Record<string, unknown>)[action.field]
            if (fieldVal == null) return false
            const numVal = typeof fieldVal === "number" ? fieldVal : parseFloat(String(fieldVal))
            const cmpVal = parseFloat(action.value)
            const strVal = String(fieldVal).toLowerCase()
            const targetStr = action.value.toLowerCase()

            switch (action.operator) {
              case "eq": return !isNaN(numVal) && !isNaN(cmpVal) ? numVal === cmpVal : strVal === targetStr
              case "gt": return !isNaN(numVal) && !isNaN(cmpVal) && numVal > cmpVal
              case "gte": return !isNaN(numVal) && !isNaN(cmpVal) && numVal >= cmpVal
              case "lt": return !isNaN(numVal) && !isNaN(cmpVal) && numVal < cmpVal
              case "lte": return !isNaN(numVal) && !isNaN(cmpVal) && numVal <= cmpVal
              case "neq": return !isNaN(numVal) && !isNaN(cmpVal) ? numVal !== cmpVal : strVal !== targetStr
              case "contains": return strVal.includes(targetStr)
              default: return strVal === targetStr
            }
          })
        }

        // Check if field exists on any candidate
        const fieldExists = snapshot.some(c => (c as unknown as Record<string, unknown>)[action.field] != null)
        if (!fieldExists && !action.keepIndices?.length) {
          console.log(`[filter_displayed] Warning: field "${action.field}" not found on any candidate`)
        }

        // Keep original ranks (do NOT re-rank) so "전체 보기" restore works correctly

        const resultText = filtered.length > 0
          ? `${fullList.length}개 중 ${filtered.length}개가 조건에 맞습니다:\n${filtered.slice(0, 5).map(c => `#${c.rank} ${c.displayCode} (${c.seriesName ?? "-"})`).join("\n")}`
          : `${fullList.length}개 제품 중 조건에 맞는 것이 없습니다. "전체 보기"로 복원할 수 있습니다.`

        const sessionState: ExplorationSessionState = {
          sessionId: prevState.sessionId ?? `ses-${Date.now()}`,
          candidateCount: prevState.candidateCount ?? candidates.length,
          appliedFilters: filters,
          narrowingHistory,
          stageHistory: prevState.stageHistory ?? [],
          resolutionStatus: prevState.resolutionStatus ?? "broad",
          resolvedInput: currentInput,
          turnCount,
          lastAskedField: prevState.lastAskedField,
          displayedCandidates: filtered,
          fullDisplayedCandidates: fullList,
          displayedSetFilter: { field: action.field, operator: action.operator, value: action.value },
          displayedChips: ["전체 보기", "추천해주세요", "처음부터 다시"],
          displayedOptions: prevState.displayedOptions ?? [],
          lastAction: "filter_displayed",
        }
        return NextResponse.json({
          text: resultText,
          purpose: "question",
          chips: ["전체 보기", "추천해주세요", "처음부터 다시"],
          isComplete: false,
          recommendation: null,
          sessionState,
          evidenceSummaries: null,
          candidateSnapshot: filtered,
          extractedField: null, requestPreparation: null,
          primaryExplanation: null, primaryFactChecked: null,
          altExplanations: [], altFactChecked: [],
          orchestratorResult: { action: action.type, agents: orchResult.agentsInvoked, opus: orchResult.escalatedToOpus },
        })
      }

      // Action: query_displayed — 표시된 제품 데이터 질의
      if (action.type === "query_displayed") {
        const fullSnapshot = prevState.displayedCandidates?.length > 0
          ? prevState.displayedCandidates
          : buildCandidateSnapshot(candidates, evidenceMap)

        // Apply topN limit if specified
        const snapshot = action.topN ? fullSnapshot.slice(0, action.topN) : fullSnapshot

        let resultText = ""
        const field = action.field

        const withValues = snapshot.map(c => ({
          candidate: c,
          value: (c as unknown as Record<string, unknown>)[field],
          numValue: (() => {
            const v = (c as unknown as Record<string, unknown>)[field]
            return typeof v === "number" ? v : (v != null ? parseFloat(String(v)) : NaN)
          })(),
        }))

        switch (action.queryType) {
          case "max": {
            const valid = withValues.filter(v => !isNaN(v.numValue))
            if (valid.length === 0) {
              resultText = `표시된 제품에서 ${field} 값을 찾을 수 없습니다.`
            } else {
              const best = valid.reduce((a, b) => a.numValue > b.numValue ? a : b)
              resultText = `${field} 최대: #${best.candidate.rank} ${best.candidate.displayCode} (${best.numValue})\n[Reference: YG-1 내부 DB]`
            }
            break
          }
          case "min": {
            const valid = withValues.filter(v => !isNaN(v.numValue))
            if (valid.length === 0) {
              resultText = `표시된 제품에서 ${field} 값을 찾을 수 없습니다.`
            } else {
              const best = valid.reduce((a, b) => a.numValue < b.numValue ? a : b)
              resultText = `${field} 최소: #${best.candidate.rank} ${best.candidate.displayCode} (${best.numValue})\n[Reference: YG-1 내부 DB]`
            }
            break
          }
          case "count": {
            if (action.condition) {
              const cmpVal = parseFloat(action.condition.value)
              const targetStr = action.condition.value.toLowerCase()
              const matching = withValues.filter(v => {
                if (v.value == null) return false
                const strVal = String(v.value).toLowerCase()
                switch (action.condition!.operator) {
                  case "eq": return !isNaN(v.numValue) && !isNaN(cmpVal) ? v.numValue === cmpVal : strVal === targetStr
                  case "gt": return !isNaN(v.numValue) && !isNaN(cmpVal) && v.numValue > cmpVal
                  case "gte": return !isNaN(v.numValue) && !isNaN(cmpVal) && v.numValue >= cmpVal
                  case "lt": return !isNaN(v.numValue) && !isNaN(cmpVal) && v.numValue < cmpVal
                  case "lte": return !isNaN(v.numValue) && !isNaN(cmpVal) && v.numValue <= cmpVal
                  case "contains": return strVal.includes(targetStr)
                  default: return strVal === targetStr
                }
              })
              resultText = `${field}${action.condition.operator === "eq" ? "=" : action.condition.operator}${action.condition.value} 인 제품: ${matching.length}개\n[Reference: YG-1 내부 DB]`
            } else {
              const nonNull = withValues.filter(v => v.value != null)
              resultText = `${field} 값이 있는 제품: ${nonNull.length}개 / 전체 ${snapshot.length}개\n[Reference: YG-1 내부 DB]`
            }
            break
          }
          case "list": {
            // For string-type fields, show unique value counts; for numeric fields, show table
            const STRING_FIELDS = new Set(["coating", "seriesName", "brand", "toolMaterial", "matchStatus", "stockStatus"])
            if (STRING_FIELDS.has(field)) {
              // Show unique values with counts
              const valueCounts = new Map<string, number>()
              for (const v of withValues) {
                const key = v.value != null ? String(v.value) : "(없음)"
                valueCounts.set(key, (valueCounts.get(key) ?? 0) + 1)
              }
              const lines = [...valueCounts.entries()].map(([val, count]) => `• ${val}: ${count}개`)
              resultText = `표시된 제품의 ${field} 분포:\n${lines.join("\n")}\n\n총 ${snapshot.length}개 제품\n[Reference: YG-1 내부 DB]`
            } else {
              // Show table for numeric fields
              const tableRows = withValues
                .filter(v => v.value != null)
                .map(v => `| #${v.candidate.rank} | ${v.candidate.displayCode} | ${v.candidate.seriesName ?? "-"} | ${v.value} |`)
              resultText = `표시된 제품의 ${field}:\n\n| # | 제품코드 | 시리즈 | ${field} |\n|---|---|---|---|\n${tableRows.join("\n")}\n\n[Reference: YG-1 내부 DB]`
            }
            break
          }
          case "find": {
            if (action.condition) {
              const cmpVal = parseFloat(action.condition.value)
              const targetStr = action.condition.value.toLowerCase()
              const matching = withValues.filter(v => {
                if (v.value == null) return false
                const strVal = String(v.value).toLowerCase()
                switch (action.condition!.operator) {
                  case "eq": return !isNaN(v.numValue) && !isNaN(cmpVal) ? v.numValue === cmpVal : strVal === targetStr
                  case "gt": return !isNaN(v.numValue) && !isNaN(cmpVal) && v.numValue > cmpVal
                  case "gte": return !isNaN(v.numValue) && !isNaN(cmpVal) && v.numValue >= cmpVal
                  case "lt": return !isNaN(v.numValue) && !isNaN(cmpVal) && v.numValue < cmpVal
                  case "lte": return !isNaN(v.numValue) && !isNaN(cmpVal) && v.numValue <= cmpVal
                  case "neq": return !isNaN(v.numValue) && !isNaN(cmpVal) ? v.numValue !== cmpVal : strVal !== targetStr
                  case "contains": return strVal.includes(targetStr)
                  default: return strVal === targetStr
                }
              })
              resultText = matching.length > 0
                ? `조건에 맞는 제품:\n${matching.slice(0, 5).map(v => `#${v.candidate.rank} ${v.candidate.displayCode} (${field}=${v.value})`).join("\n")}\n[Reference: YG-1 내부 DB]`
                : `조건에 맞는 제품이 없습니다.\n[Reference: YG-1 내부 DB]`
            } else {
              resultText = `조건을 지정해주세요. 예: "코팅이 Diamond인 건?"\n[Reference: YG-1 내부 DB]`
            }
            break
          }
          default:
            resultText = `지원하지 않는 질의 종류입니다.\n[Reference: YG-1 내부 DB]`
        }

        const sessionState: ExplorationSessionState = {
          sessionId: prevState.sessionId ?? `ses-${Date.now()}`,
          candidateCount: prevState.candidateCount ?? candidates.length,
          appliedFilters: filters,
          narrowingHistory,
          stageHistory: prevState.stageHistory ?? [],
          resolutionStatus: prevState.resolutionStatus ?? "broad",
          resolvedInput: currentInput,
          turnCount,
          lastAskedField: prevState.lastAskedField,
          displayedCandidates: snapshot,
          fullDisplayedCandidates: prevState.fullDisplayedCandidates,
          displayedSetFilter: prevState.displayedSetFilter,
          displayedChips: prevState.displayedChips ?? [],
          displayedOptions: prevState.displayedOptions ?? [],
          lastAction: "query_displayed",
        }
        return NextResponse.json({
          text: resultText,
          purpose: "general_chat",
          chips: prevState.displayedChips ?? ["추천해주세요", "처음부터 다시"],
          isComplete: false,
          recommendation: null,
          sessionState,
          evidenceSummaries: null,
          candidateSnapshot: snapshot,
          extractedField: null, requestPreparation: null,
          primaryExplanation: null, primaryFactChecked: null,
          altExplanations: [], altFactChecked: [],
          orchestratorResult: { action: action.type, agents: orchResult.agentsInvoked, opus: orchResult.escalatedToOpus },
        })
      }

      // Action: explain_product / answer_general
      if (action.type === "explain_product" || action.type === "answer_general") {
        // Use existing LLM handlers
        if (action.type === "explain_product") {
          const contextReply = await handleContextualNarrowingQuestion(
            provider, lastUserMsg.text, currentInput, candidates, prevState
          )
          if (contextReply) {
            // If already resolved, return answer directly (don't re-trigger recommendation)
            if (prevState.resolutionStatus?.startsWith("resolved")) {
              const sessionState: ExplorationSessionState = {
                sessionId: prevState.sessionId ?? `ses-${Date.now()}`,
                candidateCount: prevState.candidateCount ?? candidates.length,
                appliedFilters: filters,
                narrowingHistory,
                stageHistory: prevState.stageHistory ?? [],
                resolutionStatus: prevState.resolutionStatus,
                resolvedInput: currentInput,
                turnCount,
                lastAskedField: prevState.lastAskedField,
                displayedCandidates: prevState.displayedCandidates ?? [],
                fullDisplayedCandidates: prevState.fullDisplayedCandidates,
                displayedSetFilter: prevState.displayedSetFilter ?? null,
                displayedChips: prevState.displayedChips ?? ["대체 후보 보기", "절삭조건 알려줘", "처음부터 다시"],
                displayedOptions: prevState.displayedOptions ?? [],
                lastAction: "explain_product",
              }
              return NextResponse.json({
                text: contextReply,
                purpose: "general_chat",
                chips: prevState.displayedChips ?? ["대체 후보 보기", "절삭조건 알려줘", "처음부터 다시"],
                isComplete: false,
                recommendation: null,
                sessionState,
                evidenceSummaries: null,
                candidateSnapshot: prevState.displayedCandidates ?? null,
                extractedField: null, requestPreparation: null,
                primaryExplanation: null, primaryFactChecked: null,
                altExplanations: [], altFactChecked: [],
                orchestratorResult: { action: action.type, agents: orchResult.agentsInvoked, opus: orchResult.escalatedToOpus },
              })
            }
            return buildQuestionResponse(
              form, candidates, evidenceMap, currentInput,
              narrowingHistory, filters, turnCount, messages, provider, language,
              contextReply
            )
          }
        }

        // General chat — use preGenerated text if available (from tool-use path), otherwise call LLM
        const preGenerated = action.type === "answer_general" && action.preGenerated === true && action.message != null
        const llmResponse = preGenerated
          ? { text: action.message, chips: generateFollowUpChips(lastUserMsg.text, candidates.length) }
          : await handleGeneralChat(provider, lastUserMsg.text, currentInput, candidates, form, prevState.displayedCandidates)
        const sessionState: ExplorationSessionState = {
          sessionId: prevState.sessionId ?? `ses-${Date.now()}`,
          candidateCount: prevState.candidateCount ?? candidates.length,
          appliedFilters: filters,
          narrowingHistory,
          stageHistory: prevState.stageHistory ?? [],
          resolutionStatus: prevState.resolutionStatus ?? "broad",
          resolvedInput: currentInput,
          turnCount,
          lastAskedField: prevState.lastAskedField,
          displayedCandidates: prevState.displayedCandidates ?? [],
          fullDisplayedCandidates: prevState.fullDisplayedCandidates,
          displayedSetFilter: prevState.displayedSetFilter ?? null,
          displayedChips: llmResponse.chips,
          displayedOptions: prevState.displayedOptions ?? [],
          lastAction: "answer_general",
        }
        return NextResponse.json({
          text: llmResponse.text,
          purpose: "general_chat",
          chips: llmResponse.chips,
          isComplete: false,
          recommendation: null,
          sessionState,
          evidenceSummaries: null,
          candidateSnapshot: candidates.length > 0 ? buildCandidateSnapshot(candidates, evidenceMap) : null,
          extractedField: null,
          requestPreparation: null,
          primaryExplanation: null, primaryFactChecked: null,
          altExplanations: [], altFactChecked: [],
          orchestratorResult: { action: action.type, agents: orchResult.agentsInvoked, opus: orchResult.escalatedToOpus },
        })
      }

      // Action: redirect_off_topic
      if (action.type === "redirect_off_topic") {
        const inquiry = analyzeInquiry(lastUserMsg.text)
        const redirect = getRedirectResponse(inquiry)
        const sessionState: ExplorationSessionState = {
          sessionId: prevState.sessionId ?? `ses-${Date.now()}`,
          candidateCount: prevState.candidateCount,
          appliedFilters: filters,
          narrowingHistory,
          stageHistory: prevState.stageHistory ?? [],
          resolutionStatus: prevState.resolutionStatus ?? "broad",
          resolvedInput: currentInput,
          turnCount,
          lastAskedField: prevState.lastAskedField,
          displayedCandidates: prevState.displayedCandidates ?? [],
          fullDisplayedCandidates: prevState.fullDisplayedCandidates,
          displayedSetFilter: prevState.displayedSetFilter ?? null,
          displayedChips: redirect.chips,
          displayedOptions: prevState.displayedOptions ?? [],
          lastAction: "redirect_off_topic",
        }
        return NextResponse.json({
          text: redirect.text,
          purpose: "question",
          chips: redirect.chips,
          isComplete: false,
          recommendation: null,
          sessionState,
          evidenceSummaries: null,
          candidateSnapshot: redirect.showCandidates ? buildCandidateSnapshot(candidates, evidenceMap) : null,
          extractedField: null, requestPreparation: null,
          primaryExplanation: null, primaryFactChecked: null,
          altExplanations: [], altFactChecked: [],
        })
      }

      // Action: skip_field
      if (action.type === "skip_field") {
        const skipField = prevState.lastAskedField ?? "unknown"
        const skipFilter: AppliedFilter = {
          field: skipField, op: "skip", value: "상관없음", rawValue: "skip", appliedAt: turnCount,
        }
        filters.push(skipFilter)
        currentInput = applyFilterToInput(currentInput, skipFilter)

        const newResult = await runHybridRetrieval(currentInput, filters.filter(f => f.op !== "skip"))
        narrowingHistory.push({
          question: "follow-up", answer: lastUserMsg.text,
          extractedFilters: [skipFilter],
          candidateCountBefore: candidates.length, candidateCountAfter: newResult.candidates.length,
        })
        turnCount++

        const statusAfterSkip = checkResolution(newResult.candidates, narrowingHistory)
        if (statusAfterSkip.startsWith("resolved")) {
          return buildRecommendationResponse(form, newResult.candidates, newResult.evidenceMap, currentInput, narrowingHistory, filters, turnCount, messages, provider, language, displayedProducts)
        }
        return buildQuestionResponse(form, newResult.candidates, newResult.evidenceMap, currentInput, narrowingHistory, filters, turnCount, messages, provider, language)
      }

      // Action: continue_narrowing (apply filter from orchestrator)
      if (action.type === "continue_narrowing") {
        const filter = { ...action.filter, appliedAt: turnCount }

        // ── Zero-candidate guard: test filter before committing ──
        const testInput = applyFilterToInput(currentInput, filter)
        const testFilters = [...filters, filter]
        const testResult = await runHybridRetrieval(testInput, testFilters)

        if (testResult.candidates.length === 0) {
          // Filter would eliminate all candidates — DON'T apply it
          console.log(`[orchestrator:guard] Filter ${filter.field}=${filter.value} would result in 0 candidates — BLOCKED`)
          return buildQuestionResponse(
            form, candidates, evidenceMap, currentInput,
            narrowingHistory, filters, turnCount, messages, provider, language,
            `"${filter.value}" 조건을 적용하면 후보가 없습니다. 현재 ${candidates.length}개 후보에서 다른 조건을 선택해주세요.`
          )
        }

        // Safe to apply
        filters.push(filter)
        currentInput = testInput
        const newCandidates = testResult.candidates
        const prevCandidateCount = candidates.length  // always use current pool count, not stale session state

        narrowingHistory.push({
          question: prevState.narrowingHistory?.length ? "follow-up" : "initial",
          answer: lastUserMsg.text,
          extractedFilters: [filter],
          candidateCountBefore: prevCandidateCount,
          candidateCountAfter: newCandidates.length,
        })

        // Stage snapshot
        const existingStages = prevState.stageHistory ?? []
        const newStage: NarrowingStage = {
          stepIndex: turnCount,
          stageName: `${filter.field}_${filter.value}`,
          filterApplied: filter,
          candidateCount: newCandidates.length,
          resolvedInputSnapshot: { ...currentInput },
          filtersSnapshot: [...filters],
        }
        const updatedStages = [...existingStages, newStage]

        console.log(`[orchestrator:filter] ${filter.field}=${filter.value} | ${prevCandidateCount}→${newCandidates.length} candidates | stages: ${updatedStages.map(s => s.stageName).join(" → ")}`)

        turnCount++

        const newStatus = checkResolution(newCandidates, narrowingHistory)
        if (newStatus.startsWith("resolved")) {
          return buildRecommendationResponse(form, newCandidates, testResult.evidenceMap, currentInput, narrowingHistory, filters, turnCount, messages, provider, language, displayedProducts)
        }

        return buildQuestionResponse(form, newCandidates, testResult.evidenceMap, currentInput, narrowingHistory, filters, turnCount, messages, provider, language, undefined, updatedStages)
      }
    }
  }

  // ── Step 3: Determine what to do next ──────────────────────
  const status = checkResolution(candidates, narrowingHistory)

  if (status.startsWith("resolved") && turnCount > 0) {
    // Already resolved — show results
    return buildRecommendationResponse(
      form, candidates, evidenceMap, currentInput, narrowingHistory,
      filters, turnCount, messages, provider, language, displayedProducts
    )
  }

  // Not resolved (or first call) — ask a question
  return buildQuestionResponse(
    form, candidates, evidenceMap, currentInput, narrowingHistory,
    filters, turnCount, messages, provider, language
  )
}

// ── Build Question Response ──────────────────────────────────
async function buildQuestionResponse(
  form: ProductIntakeForm,
  candidates: ScoredProduct[],
  evidenceMap: Map<string, EvidenceSummary>,
  input: RecommendationInput,
  history: NarrowingTurn[],
  filters: AppliedFilter[],
  turnCount: number,
  messages: ChatMessage[],
  provider: ReturnType<typeof getProvider>,
  language: AppLanguage,
  overrideText?: string,
  existingStageHistory?: NarrowingStage[]
): Promise<Response> {
  const question = selectNextQuestion(input, candidates, history)

  // Build stage history — snapshot current state if we don't have one yet
  const stageHistory: NarrowingStage[] = existingStageHistory
    ? [...existingStageHistory]
    : buildStageHistoryFromFilters(filters, input, candidates.length)

  // Build candidate snapshot for UI (before session state so we can persist it)
  const candidateSnapshot = buildCandidateSnapshot(candidates, evidenceMap)
  const chips = question?.chips ?? []

  // Build structured displayedOptions from chips for numbered selection
  const displayedOptions = buildDisplayedOptions(chips, question?.field ?? "unknown")

  // Build session state for client — single source of truth
  const sessionState: ExplorationSessionState = {
    sessionId: `ses-${Date.now()}`,
    candidateCount: candidates.length,
    appliedFilters: filters,
    narrowingHistory: history,
    stageHistory,
    resolutionStatus: checkResolution(candidates, history),
    resolvedInput: input,
    turnCount,
    lastAskedField: question?.field ?? undefined,
    displayedCandidates: candidateSnapshot,
    fullDisplayedCandidates: undefined,
    displayedSetFilter: null,
    displayedChips: chips,
    displayedOptions,
    lastAction: "continue_narrowing",
  }

  // Debug: log narrowing state
  logNarrowingState("question", sessionState, question?.field ?? null)

  // If no question (resolved or out of questions), go to recommendation
  // BUT: if we have overrideText (explanation/undo feedback), show it instead of re-recommending
  if (!question && !overrideText) {
    return buildRecommendationResponse(
      form, candidates, evidenceMap, input, history,
      filters, turnCount, messages, provider, language, snapshotToDisplayed(candidateSnapshot)
    )
  }

  // candidateSnapshot already computed above (persisted in sessionState)

  // LLM-polish the question text (or use deterministic)
  let responseText = overrideText ?? question?.questionText ?? ""
  let responseChips = question?.chips ?? chips

  if (overrideText) {
    // Skip LLM polish when we have an override (e.g. irrelevant input nudge)
  } else if (provider.available() && messages.length === 0) {
    // First call: generate greeting
    try {
      const systemPrompt = buildSystemPrompt(language)
      const sessionCtx = buildSessionContext(form, sessionState, candidates.length, snapshotToDisplayed(candidateSnapshot))
      const greetingPrompt = buildGreetingPrompt(sessionCtx, question, candidates.length, language)

      const raw = await provider.complete(systemPrompt, [
        { role: "user", content: greetingPrompt }
      ], 800)

      const parsed = safeParseJSON(raw)
      if (typeof parsed?.responseText === "string") {
        responseText = parsed.responseText
      }
    } catch (e) {
      console.warn("[recommend] LLM greeting failed:", e)
    }
  } else if (provider.available() && messages.length > 0) {
    // Follow-up: polish the question
    try {
      const systemPrompt = buildSystemPrompt(language)
      const sessionCtx = buildSessionContext(form, sessionState, candidates.length, snapshotToDisplayed(candidateSnapshot))
      const raw = await provider.complete(systemPrompt, [
        { role: "user", content: `${sessionCtx}\n\n다음 질문을 자연스럽고 간결한 ${language === "ko" ? "한국어" : "영어"}로 다듬어주세요: "${question?.questionText ?? ""}"\n현재 후보 ${candidates.length}개.\nJSON으로 응답: { "responseText": "...", "extractedParams": {}, "isComplete": false, "skipQuestion": false }` }
      ], 300)

      const parsed = safeParseJSON(raw)
      if (typeof parsed?.responseText === "string") {
        responseText = parsed.responseText
      }
    } catch (e) {
      console.warn("[recommend] LLM question polish failed:", e)
    }
  }

  // Run request preparation for metadata
  const requestPrep = prepareRequest(form, messages, sessionState, input, candidates.length)

  return NextResponse.json({
    text: responseText,
    purpose: messages.length === 0 ? "greeting" : "question",
    chips: responseChips,
    isComplete: false,
    recommendation: null,
    sessionState,
    evidenceSummaries: null,
    candidateSnapshot,
    extractedField: null,
    requestPreparation: requestPrep,
    primaryExplanation: null,
    primaryFactChecked: null,
    altExplanations: [],
    altFactChecked: [],
  })
}

// ── Build Recommendation Response ────────────────────────────
async function buildRecommendationResponse(
  form: ProductIntakeForm,
  candidates: ScoredProduct[],
  evidenceMap: Map<string, EvidenceSummary>,
  input: RecommendationInput,
  history: NarrowingTurn[],
  filters: AppliedFilter[],
  turnCount: number,
  messages: ChatMessage[],
  provider: ReturnType<typeof getProvider>,
  language: AppLanguage,
  displayedProducts: DisplayedProduct[] | null = null
): Promise<Response> {
  const { primary, alternatives, status } = classifyHybridResults({ candidates, evidenceMap, totalConsidered: candidates.length, filtersApplied: filters })
  const warnings = primary ? buildWarnings(primary, input) : ["조건에 맞는 제품을 찾지 못했습니다"]
  const rationale = primary ? buildRationale(primary, input) : []

  // Add intake-specific warnings
  if (form.material.status === "unknown") warnings.push("소재 미지정 — 전체 소재 대상 검색")
  if (form.diameterInfo.status === "unknown") warnings.push("직경 미지정 — 직경 기준 필터 없음")

  const deterministicSummary = buildDeterministicSummary({
    status,
    query: input,
    primaryProduct: primary,
    alternatives,
    warnings,
    rationale,
    sourceSummary: [],
    deterministicSummary: "",
    llmSummary: null,
    totalCandidatesConsidered: candidates.length,
  })

  // Build evidence summaries for top products
  const evidenceSummaries: EvidenceSummary[] = []
  if (primary) {
    const es = evidenceMap.get(primary.product.normalizedCode)
    if (es) evidenceSummaries.push(es)
  }
  for (const alt of alternatives) {
    const es = evidenceMap.get(alt.product.normalizedCode)
    if (es) evidenceSummaries.push(es)
  }

  // ── NEW: Build explanation + fact check for primary ────────
  let primaryExplanation: RecommendationExplanation | null = null
  let primaryFactChecked: FactCheckedRecommendation | null = null
  let altExplanations: RecommendationExplanation[] = []
  let altFactChecked: FactCheckedRecommendation[] = []

  if (primary) {
    const primaryEvidence = evidenceMap.get(primary.product.normalizedCode) ?? null
    primaryExplanation = buildExplanation(primary, input, primaryEvidence)
    primaryFactChecked = await runFactCheck(primary, input, primaryEvidence, primaryExplanation)

    // Build explanations for alternatives too
    for (const alt of alternatives) {
      const altEvidence = evidenceMap.get(alt.product.normalizedCode) ?? null
      const altExpl = buildExplanation(alt, input, altEvidence)
      altExplanations.push(altExpl)
      altFactChecked.push(await runFactCheck(alt, input, altEvidence, altExpl))
    }
  }

  const recommendation: RecommendationResult = {
    status,
    query: input,
    primaryProduct: primary,
    alternatives,
    warnings,
    rationale,
    sourceSummary: primary ? buildSourceSummary(primary) : [],
    deterministicSummary,
    llmSummary: null,
    totalCandidatesConsidered: candidates.length,
  }

  // LLM summary with explanation-aware prompt
  if (provider.available() && primary && primaryFactChecked && primaryExplanation) {
    try {
      const systemPrompt = buildSystemPrompt(language)
      const llmSessionState: ExplorationSessionState = {
        sessionId: `ses-${Date.now()}`,
        candidateCount: candidates.length,
        appliedFilters: filters,
        narrowingHistory: history,
        stageHistory: buildStageHistoryFromFilters(filters, input, candidates.length),
        resolutionStatus: checkResolution(candidates, history),
        resolvedInput: input,
        turnCount,
        displayedCandidates: buildCandidateSnapshot(candidates, evidenceMap),
        fullDisplayedCandidates: undefined,
        displayedSetFilter: null,
        displayedChips: [],
        displayedOptions: [],
        lastAction: "show_recommendation",
      }
      const sessionCtx = buildSessionContext(form, llmSessionState, candidates.length, snapshotToDisplayed(llmSessionState.displayedCandidates))

      // Use new explanation-aware prompt — include per-product evidence
      const resultPrompt = buildExplanationResultPrompt(
        sessionCtx,
        primaryFactChecked,
        primaryExplanation,
        alternatives.map(a => {
          const altEvidence = evidenceMap.get(a.product.normalizedCode)
          return {
              displayCode: a.product.displayCode,
              matchStatus: a.matchStatus,
              score: a.score,
              bestCondition: altEvidence?.bestCondition
                ? { ...altEvidence.bestCondition } as Record<string, string | null>
                : null,
              sourceCount: altEvidence?.sourceCount ?? 0,
            }
        }),
        warnings,
        language
      )

      const raw = await provider.complete(systemPrompt, [
        { role: "user", content: resultPrompt }
      ], 1500)

      const parsed = safeParseJSON(raw)
      if (parsed?.responseText) {
        recommendation.llmSummary = parsed.responseText as string
      } else if (raw.trim() && !raw.trim().startsWith("{") && !raw.trim().startsWith("[")) {
        // Only use raw text if it's NOT malformed JSON (prevents JSON leaking into UI)
        recommendation.llmSummary = raw.trim()
      }
    } catch (e) {
      console.warn("[recommend] LLM result summary failed:", e)
    }
  }

  const candidateSnapshot = buildCandidateSnapshot(candidates, evidenceMap)
  const followUpChips = getFollowUpChips(recommendation)

  const sessionState: ExplorationSessionState = {
    sessionId: `ses-${Date.now()}`,
    candidateCount: candidates.length,
    appliedFilters: filters,
    narrowingHistory: history,
    stageHistory: buildStageHistoryFromFilters(filters, input, candidates.length),
    resolutionStatus: checkResolution(candidates, history),
    resolvedInput: input,
    turnCount,
    displayedCandidates: candidateSnapshot,
    fullDisplayedCandidates: candidateSnapshot,
    displayedSetFilter: null,
    displayedChips: followUpChips,
    displayedOptions: [],
    lastAction: "show_recommendation",
  }

  // Run request preparation for metadata
  const requestPrep = prepareRequest(form, messages, sessionState, input, candidates.length)

  let responseText = recommendation.llmSummary ?? deterministicSummary

  // ── Inject brand name if LLM forgot ────────────────────────
  if (primary && primary.product.brand) {
    const brandName = primary.product.brand
    const hasBrand = responseText.includes(brandName) || /브랜드명/.test(responseText)
    if (!hasBrand) {
      const brandHeader = `**브랜드명:** ${brandName} | **제품코드:** ${primary.product.displayCode}`
      responseText = `${brandHeader}\n\n${responseText}`
    }
  }

  // candidateSnapshot already computed above (persisted in sessionState)

  // Slack 알림 (비동기)
  if (primary) {
    notifyRecommendation({
      productCode: primary.product.displayCode,
      brand: primary.product.brand,
      seriesName: primary.product.seriesName,
      matchStatus: status,
      score: primary.score,
      query: `직경:${input.diameterMm ?? "?"}mm 소재:${input.material ?? "?"} 가공:${input.operationType ?? "?"}`,
    }).catch(() => {})
  }

  return NextResponse.json({
    text: status === "none"
      ? "조건에 맞는 제품을 찾지 못했습니다. 직경이나 소재 조건을 조정해보세요."
      : responseText,
    purpose: "recommendation",
    chips: followUpChips,
    isComplete: true,
    recommendation,
    sessionState,
    evidenceSummaries: evidenceSummaries.length > 0 ? evidenceSummaries : null,
    candidateSnapshot,
    extractedField: null,
    // New fields
    requestPreparation: requestPrep,
    primaryExplanation,
    primaryFactChecked: primaryFactChecked ? serializeFactChecked(primaryFactChecked) : null,
    altExplanations,
    altFactChecked: altFactChecked.map(fc => serializeFactChecked(fc)),
  })
}

// ── Contextual Narrowing Question Handler ────────────────────
async function handleContextualNarrowingQuestion(
  provider: ReturnType<typeof getProvider>,
  userMessage: string,
  _currentInput: RecommendationInput,
  candidates: ScoredProduct[],
  prevState: ExplorationSessionState
): Promise<string | null> {
  const lastField = prevState.lastAskedField ?? "unknown"

  // Build context about what options exist in candidates for this field
  const fieldExplanations: Record<string, () => string> = {
    coating: () => {
      const coatings = [...new Set(candidates.map(c => c.product.coating).filter(Boolean))]
      return `코팅 종류에 대해 설명드리겠습니다.

현재 후보 제품들의 코팅 종류:
${coatings.map(c => `• ${c}`).join("\n")}

간단 설명:
• DLC (Diamond-Like Carbon) — 알루미늄/비철금속에 최적. 낮은 마찰, 높은 내마모성
• TiAlN — 고온 가공에 적합. 내열성 우수 (강, 스테인리스)
• AlCrN — 고경도 소재 가공용. TiAlN보다 더 높은 내열성
• TiCN — 범용. 중간 경도, 탄소강/합금강에 적합
• Blue Coating — YG-1 자체 코팅. 범용 가공에 적합
• 무코팅 — 알루미늄/구리 등 연질 소재에 사용

모르시면 "상관없음"을 선택하면 전체 후보에서 추천해드립니다.`
    },
    fluteCount: () => {
      const flutes = [...new Set(candidates.map(c => c.product.fluteCount).filter(Boolean))].sort()
      return `날 수(flute)에 대해 설명드리겠습니다.

현재 후보 제품 날 수: ${flutes.join(", ")}날

• 2날 — 알루미늄/비철 가공, 칩 배출 우수 (황삭에 유리)
• 3날 — 범용. 황삭~정삭 겸용
• 4날 — 정삭/고정밀 가공. 표면 품질 우수
• 6날 이상 — 고이송 가공, 높은 생산성

모르시면 "상관없음"을 선택해주세요.`
    },
    diameterRefine: () => {
      const diameters = [...new Set(candidates.map(c => c.product.diameterMm).filter((d): d is number => d != null))].sort((a, b) => a - b)
      const min = diameters[0]
      const max = diameters[diameters.length - 1]
      return `직경은 가공하려는 형상과 장비에 따라 선택합니다.

현재 후보 직경 범위: ${min}mm ~ ${max}mm
가용 직경: ${diameters.slice(0, 10).join(", ")}mm${diameters.length > 10 ? " ..." : ""}

직경을 모르시면 "상관없음"을 선택해주세요.`
    },
  }

  const explainer = fieldExplanations[lastField]
  if (explainer) return explainer()

  // Fallback: use LLM for other fields
  if (provider.available()) {
    try {
      const raw = await provider.complete(
        "당신은 YG-1 절삭공구 전문 엔지니어입니다. 사용자가 추천 대화 중 현재 질문에 대해 '그게 뭐야?' 같은 질문을 했습니다. 간결하게 3-4문장으로 설명하세요.",
        [{ role: "user", content: `현재 질문 필드: ${lastField}\n사용자 질문: ${userMessage}\n현재 후보 수: ${candidates.length}개` }],
        400
      )
      if (raw?.trim()) return raw.trim()
    } catch { /* fallback below */ }
  }

  return `현재 ${candidates.length}개 후보가 있습니다. 잘 모르시면 "상관없음"을 선택해주세요.`
}

const DIRECT_PRODUCT_CODE_PATTERN = /\b([A-Z][A-Z0-9-]{4,})\b/i
const DIRECT_SERIES_CODE_PATTERN = /\b([A-Z]\d[A-Z]\d{2,}[A-Z]?)\b/i
const CUTTING_CONDITION_QUERY_PATTERN = /절삭조건|가공조건|vc|fz|이송|회전수|rpm|feed/i
const INVENTORY_QUERY_PATTERN = /재고|stock|inventory|available|availability|수량|남았/i

function normalizeLookupCode(value: string): string {
  return value.toUpperCase().replace(/[\s-]/g, "").trim()
}

function escapeMarkdownTableCell(value: string | number | null | undefined): string {
  if (value === null || value === undefined || value === "") return "-"
  return String(value).replace(/\|/g, "/").replace(/\n/g, " ").trim() || "-"
}

function buildMarkdownTable(headers: string[], rows: Array<Array<string | number | null | undefined>>): string {
  const headerRow = `| ${headers.map(escapeMarkdownTableCell).join(" | ")} |`
  const dividerRow = `| ${headers.map(() => "---").join(" | ")} |`
  const bodyRows = rows.map(row => `| ${row.map(escapeMarkdownTableCell).join(" | ")} |`)
  return [headerRow, dividerRow, ...bodyRows].join("\n")
}

function formatStockStatusLabel(stockStatus: "instock" | "limited" | "outofstock" | "unknown"): string {
  if (stockStatus === "instock") return "재고 있음"
  if (stockStatus === "limited") return "소량 재고"
  if (stockStatus === "outofstock") return "재고 없음"
  return "재고 미확인"
}

function summarizeInventoryRowsByWarehouse(rows: Array<{ warehouseOrRegion: string; quantity: number | null }>): Array<{ warehouseOrRegion: string; quantity: number }> {
  return Array.from(
    rows.reduce((acc, row) => {
      if (row.quantity === null) return acc
      const key = row.warehouseOrRegion?.trim()
      if (!key) return acc
      acc.set(key, (acc.get(key) ?? 0) + row.quantity)
      return acc
    }, new Map<string, number>())
  )
    .map(([warehouseOrRegion, quantity]) => ({ warehouseOrRegion, quantity }))
    .sort((a, b) => b.quantity - a.quantity || a.warehouseOrRegion.localeCompare(b.warehouseOrRegion))
}

function getLatestInventorySnapshotDateFromRows(rows: Array<{ snapshotDate: string | null }>): string | null {
  const dates = rows
    .map(row => row.snapshotDate)
    .filter((value): value is string => typeof value === "string" && value.trim().length > 0)
    .sort()
  return dates.length > 0 ? dates[dates.length - 1] : null
}

async function handleDirectInventoryQuestion(
  userMessage: string,
  prevState: ExplorationSessionState
): Promise<{ text: string; chips: string[] } | null> {
  if (!INVENTORY_QUERY_PATTERN.test(userMessage)) return null

  const productCodeMatch = userMessage.match(DIRECT_PRODUCT_CODE_PATTERN)
  const lookupCode = normalizeLookupCode(productCodeMatch?.[1] ?? "")
  if (!lookupCode) return null

  const product = await ProductRepo.findByCode(lookupCode).catch(() => null)
  const inventoryRows = await InventoryRepo.getByEdpAsync(lookupCode)
  const totalStock = await InventoryRepo.totalStockAsync(lookupCode)
  const stockStatus = await InventoryRepo.stockStatusAsync(lookupCode)
  const warehouseSummary = summarizeInventoryRowsByWarehouse(inventoryRows)
  const latestSnapshotDate = getLatestInventorySnapshotDateFromRows(inventoryRows)

  if (totalStock !== null || warehouseSummary.length > 0) {
    const summaryTable = buildMarkdownTable(
      ["항목", "값"],
      [
        ["제품코드", lookupCode],
        ["시리즈", product?.seriesName ?? "-"],
        ["직경", product?.diameterMm != null ? `φ${product.diameterMm}mm` : "-"],
        ["전체 지역 합산 재고", totalStock != null ? `${totalStock}개` : "-"],
        ["재고 상태", formatStockStatusLabel(stockStatus)],
        ["기준일", latestSnapshotDate ?? "-"],
      ]
    )
    const inventoryTable = buildMarkdownTable(
      ["지역", "수량"],
      warehouseSummary.length > 0
        ? warehouseSummary.slice(0, 8).map(row => [row.warehouseOrRegion, `${row.quantity}개`])
        : [["지역별 재고", "없음"]]
    )

    return {
      text: [
        `${lookupCode}의 재고 데이터를 내부 데이터에서 조회했습니다.`,
        "",
        summaryTable,
        "",
        inventoryTable,
        "",
        "[Reference: YG-1 내부 재고 데이터]",
      ].join("\n"),
      chips: ["다른 제품 재고", "추천 제품 보기", "처음부터 다시"],
    }
  }

  if (product) {
    return {
      text: [
        `${lookupCode} 제품은 찾았지만, 매칭되는 재고 데이터는 없습니다.`,
        "",
        buildMarkdownTable(
          ["항목", "값"],
          [
            ["제품코드", lookupCode],
            ["시리즈", product.seriesName ?? "-"],
            ["직경", product.diameterMm != null ? `φ${product.diameterMm}mm` : "-"],
            ["재고", "매칭 데이터 없음"],
          ]
        ),
        "",
        "[Reference: YG-1 내부 재고 데이터]",
      ].join("\n"),
      chips: ["다른 제품 재고", "추천 제품 보기", "처음부터 다시"],
    }
  }

  if (prevState.displayedCandidates?.length > 0) {
    return {
      text: [
        `${lookupCode}에 대한 재고 데이터를 내부 데이터에서 찾지 못했습니다.`,
        "현재 표시된 후보의 제품코드로 다시 물어보시면 내부 재고 기준으로 조회해드릴 수 있습니다.",
        "[Reference: YG-1 내부 재고 데이터]",
      ].join("\n"),
      chips: ["후보 제품 보기", "추천 제품 보기", "처음부터 다시"],
    }
  }

  return {
    text: [
      `${lookupCode}에 대한 재고 데이터를 내부 데이터에서 찾지 못했습니다.`,
      "제품코드를 다시 확인해주세요.",
      "[Reference: YG-1 내부 재고 데이터]",
    ].join("\n"),
    chips: ["제품 추천", "다른 제품 재고", "처음부터 다시"],
  }
}

function formatConditionLabel(condition: {
  isoGroup: string | null
  cuttingType: string | null
  diameterMm: number | null
  conditions: { Vc: string | null; fz: string | null; ap: string | null; ae: string | null; n: string | null; vf: string | null }
}): string {
  const scope: string[] = []
  if (condition.isoGroup) scope.push(`ISO ${condition.isoGroup}`)
  if (condition.cuttingType) scope.push(condition.cuttingType)
  if (condition.diameterMm != null) scope.push(`φ${condition.diameterMm}mm`)

  const values = [
    condition.conditions.Vc ? `Vc ${condition.conditions.Vc}` : null,
    condition.conditions.fz ? `fz ${condition.conditions.fz}` : null,
    condition.conditions.ap ? `ap ${condition.conditions.ap}` : null,
    condition.conditions.ae ? `ae ${condition.conditions.ae}` : null,
    condition.conditions.n ? `n ${condition.conditions.n}` : null,
    condition.conditions.vf ? `vf ${condition.conditions.vf}` : null,
  ].filter(Boolean)

  return `- ${scope.join(" | ")}: ${values.join(", ")}`
}

async function handleDirectCuttingConditionQuestion(
  userMessage: string,
  currentInput: RecommendationInput,
  prevState: ExplorationSessionState
): Promise<{ text: string; chips: string[] } | null> {
  if (!CUTTING_CONDITION_QUERY_PATTERN.test(userMessage)) return null

  const productCodeMatch = userMessage.match(DIRECT_PRODUCT_CODE_PATTERN)
  const seriesCodeMatch = userMessage.match(DIRECT_SERIES_CODE_PATTERN)
  const lookupCode = normalizeLookupCode(productCodeMatch?.[1] ?? seriesCodeMatch?.[1] ?? "")
  if (!lookupCode) return null

  const product = await ProductRepo.findByCode(lookupCode)
  const isoGroup = currentInput.material ? resolveMaterialTag(currentInput.material) : null

  if (product) {
    const chunks = await EvidenceRepo.findForProduct(lookupCode, {
      seriesName: product.seriesName,
      diameterMm: product.diameterMm,
      isoGroup,
    })

    if (chunks.length > 0) {
      const summaryTable = buildMarkdownTable(
        ["항목", "값"],
        [
          ["제품코드", lookupCode],
          ["시리즈", product.seriesName ?? "-"],
          ["직경", product.diameterMm != null ? `φ${product.diameterMm}mm` : "-"],
          ["ISO 소재", isoGroup ? `ISO ${isoGroup}` : "-"],
        ]
      )
      const conditionTable = buildMarkdownTable(
        ["ISO", "가공", "직경", "Vc", "fz", "ap", "ae", "n", "vf"],
        chunks.slice(0, 5).map(chunk => [
          chunk.isoGroup ? `ISO ${chunk.isoGroup}` : "-",
          chunk.cuttingType,
          chunk.diameterMm != null ? `φ${chunk.diameterMm}mm` : "-",
          chunk.conditions.Vc,
          chunk.conditions.fz,
          chunk.conditions.ap,
          chunk.conditions.ae,
          chunk.conditions.n,
          chunk.conditions.vf,
        ])
      )

      const text = [
        `${lookupCode}의 절삭조건을 내부 DB에서 조회했습니다.`,
        "",
        summaryTable,
        "",
        conditionTable,
        "",
        "[Reference: YG-1 내부 DB]",
      ].join("\n")

      return {
        text,
        chips: ["다른 소재 조건도 보여줘", "추천 제품 보기", "처음부터 다시"],
      }
    }

    return {
      text: [
        `${lookupCode} 제품은 내부 DB에서 찾았지만, 매칭되는 절삭조건 데이터는 찾지 못했습니다.`,
        "",
        buildMarkdownTable(
          ["항목", "값"],
          [
            ["제품코드", lookupCode],
            ["시리즈", product.seriesName ?? "-"],
            ["직경", product.diameterMm != null ? `φ${product.diameterMm}mm` : "-"],
            ["절삭조건", "매칭 데이터 없음"],
          ]
        ),
        "",
        "[Reference: YG-1 내부 DB]",
      ].join("\n"),
      chips: ["시리즈 기준으로 다시 보기", "추천 제품 보기", "처음부터 다시"],
    }
  }

  const seriesChunks = await EvidenceRepo.findBySeriesName(lookupCode, {
    isoGroup,
    diameterMm: currentInput.diameterMm,
  })
  if (seriesChunks.length > 0) {
    const summaryTable = buildMarkdownTable(
      ["항목", "값"],
      [
        ["시리즈", lookupCode],
        ["ISO 소재", isoGroup ? `ISO ${isoGroup}` : "-"],
        ["직경 필터", currentInput.diameterMm != null ? `φ${currentInput.diameterMm}mm` : "-"],
      ]
    )
    const seriesTable = buildMarkdownTable(
      ["ISO", "가공", "직경", "Vc", "fz", "ap", "ae", "n", "vf"],
      seriesChunks.slice(0, 5).map(chunk => [
        chunk.isoGroup ? `ISO ${chunk.isoGroup}` : "-",
        chunk.cuttingType,
        chunk.diameterMm != null ? `φ${chunk.diameterMm}mm` : "-",
        chunk.conditions.Vc,
        chunk.conditions.fz,
        chunk.conditions.ap,
        chunk.conditions.ae,
        chunk.conditions.n,
        chunk.conditions.vf,
      ])
    )
    return {
      text: [
        `${lookupCode} 시리즈 기준 절삭조건을 내부 DB에서 조회했습니다.`,
        "",
        summaryTable,
        "",
        seriesTable,
        "",
        "[Reference: YG-1 내부 DB]",
      ].join("\n"),
      chips: ["추천 제품 보기", "다른 소재 조건도 보여줘", "처음부터 다시"],
    }
  }

  if (prevState.displayedCandidates?.length > 0) {
    return {
      text: [
        `${lookupCode}에 대한 절삭조건은 내부 DB에서 찾지 못했습니다.`,
        "현재 추천 결과의 제품코드/시리즈로 다시 물어보시면 내부 DB 기준으로 조회해드릴 수 있습니다.",
        "[Reference: YG-1 내부 DB]",
      ].join("\n"),
      chips: ["후보 제품 보기", "추천 제품 보기", "처음부터 다시"],
    }
  }

  return {
    text: [
      `${lookupCode}에 대한 절삭조건은 내부 DB에서 찾지 못했습니다.`,
      "제품코드 또는 시리즈명을 다시 확인해주세요.",
      "[Reference: YG-1 내부 DB]",
    ].join("\n"),
    chips: ["제품 추천", "시리즈 검색", "처음부터 다시"],
  }
}

// ── Web Search for Knowledge Questions ────────────────────────

const CUTTING_KNOWLEDGE_PATTERNS = /절삭|공구|엔드밀|드릴|인서트|코팅|소재|가공|선반|밀링|CNC|초경|CBN|세라믹|황삭|정삭|면취|보링|리머|탭|나사|칩|인선|마모|수명|이송|회전|절입|쿨란트|치핑|버|진동|채터|tialn|alcrn|dlc|hss|carbide|endmill|milling|turning|drilling/i

async function searchWebForKnowledge(query: string, purpose: "cutting_knowledge" | "general_knowledge"): Promise<string | null> {
  const apiKey = process.env.ANTHROPIC_API_KEY || process.env.ANTHROPIC_KEY || ""
  if (!apiKey) return null

  try {
    const Anthropic = (await import("@anthropic-ai/sdk")).default
    const searchClient = new Anthropic({ apiKey })

    const resp = await searchClient.messages.create({
      model: "claude-sonnet-4-20250514" as Parameters<typeof searchClient.messages.create>["0"]["model"],
      max_tokens: 1024,
      tools: [{ type: "web_search_20250305" as const, name: "web_search", max_uses: 3 }],
      messages: [{
        role: "user",
        content: `다음 질문에 대해 웹 검색으로 전문적인 정보를 찾아 한국어로 정리해주세요.\n\n질문: ${query}\n\n규칙:\n- 구체적 수치와 비교 포함\n- 3~5문장으로 핵심만\n- 출처가 있으면 간단히 언급`,
      }],
    })

    const textBlocks = resp.content.filter(
      (b): b is { type: "text"; text: string; citations?: unknown[] } => b.type === "text"
    )
    const text = textBlocks.map((b) => b.text).join("\n").trim()
    return text || null
  } catch (e) {
    console.warn("[recommend] Web search failed:", e)
    return null
  }
}

// ── General Chat Handler (non-product questions) ──────────────
// Unified handler: greetings, general knowledge, off-domain, system questions
async function handleGeneralChat(
  provider: ReturnType<typeof getProvider>,
  userMessage: string,
  _currentInput: RecommendationInput,
  candidates: ScoredProduct[],
  form: ProductIntakeForm,
  displayedCandidatesContext?: CandidateSnapshot[],
): Promise<{ text: string; chips: string[] }> {
  const clean = userMessage.trim()
  const candidateCount = candidates.length

  // Fallback if LLM not available
  if (!provider.available()) {
    return {
      text: "안녕하세요! YG-1 절삭공구 추천 시스템입니다. 가공 조건을 알려주시면 최적의 제품을 추천해드립니다.",
      chips: ["스테인리스 가공", "알루미늄 10mm", "엔드밀 추천", "절삭조건 문의"],
    }
  }

  // Detect if this is a cutting tool knowledge question → web search
  const isCuttingKnowledge = CUTTING_KNOWLEDGE_PATTERNS.test(clean)
  const isKnowledgeQuestion = /차이|비교|뭐야|알려|설명|원리|방법|팁|주의|장단점|특징|어떤|언제|왜|어떻게|추천|좋은/i.test(clean)
  const needsWebSearch = isCuttingKnowledge && isKnowledgeQuestion

  let webSearchResult: string | null = null
  if (needsWebSearch) {
    webSearchResult = await searchWebForKnowledge(clean, "cutting_knowledge")
  }

  // Build context about current session for richer answers
  const sessionContext = candidateCount > 0
    ? `현재 ${candidateCount}개 후보 제품이 검색되어 있습니다.`
    : ""

  const formContext = form.material.status === "known" || form.operationType.status === "known"
    ? `사용자 입력 조건: 소재=${form.material.status === "known" ? form.material.value : "미지정"}, 가공=${form.operationType.status === "known" ? form.operationType.value : "미지정"}`
    : ""

  // Build displayed products context for grounded answers
  const displayedContext = displayedCandidatesContext && displayedCandidatesContext.length > 0
    ? `\n═══ 현재 표시된 추천 제품 (사용자가 "이 중", "위 제품", "상위 N개" 등으로 참조 시 반드시 이 목록에서 답하라) ═══\n${displayedCandidatesContext.slice(0, 10).map(c =>
      `#${c.rank} ${c.displayCode}${c.displayLabel ? ` [${c.displayLabel}]` : ""} | ${c.brand ?? "?"} | ${c.seriesName ?? "?"} | φ${c.diameterMm ?? "?"}mm | ${c.fluteCount ?? "?"}F | ${c.coating ?? "?"} | ${c.materialTags.join("/") || "?"} | ${c.matchStatus} ${c.score}점`
    ).join("\n")}`
    : ""

  const webContext = webSearchResult
    ? `\n═══ 웹 검색 참고 자료 (내부 DB 외부) ═══\n${webSearchResult}\n위 웹 검색 결과를 참고하여 답변하되, "📌 웹 검색 참고 (내부 DB 외부 정보)" 라고 출처를 밝혀주세요.`
    : ""

  try {
    const systemPrompt = `당신은 YG-1의 절삭공구 전문 AI 어시스턴트입니다.
YG-1은 한국의 세계적인 절삭공구 제조사입니다.

═══ 역할 ═══
- 절삭공구, 가공 기술, 소재, 코팅에 대한 전문 지식
- CNC 가공 현장 경험 기반 실용적 조언
- 시스템/화면 용어 설명
- 절삭공구 무관한 질문에도 유연하게 대응

═══ 시스템 정보 (사용자가 물어볼 때) ═══
- 약 36,000개 YG-1 절삭공구 제품 데이터 보유
- 스코어링: 직경(40pt), 소재(20pt), 날수(15pt), 가공방식(15pt), 절삭조건(10pt), 코팅(5pt), 완성도(5pt) = 110점 만점
- 정확 매칭(75%↑), 근사 매칭(45~75%), 매칭 없음(45%↓)
- 팩트 체크: 추천 제품 스펙이 DB 데이터와 일치하는지 자동 검증
- ISO 소재 분류: P=탄소강, M=스테인리스, K=주철, N=비철/알루미늄, S=내열합금/티타늄, H=고경도강
- 할루시네이션 방지: 모든 데이터는 DB에서만 인용

═══ 기술 지식 ═══
## ISO 소재 분류
- P (파란색): 탄소강, 합금강, 공구강
- M (노란색): 스테인리스강 — 가공경화 주의
- K (빨간색): 주철, CGI — 짧은 칩, 마모 주의
- N (초록색): 알루미늄, 비철 — 고속 가공, 구성인선 주의
- S (갈색): 내열합금, 티타늄 — 저속, 고압 쿨란트 필수
- H (회색): 고경도강 HRc 40~65

## 코팅
- TiAlN: 고온 내마모, 고경도강/SUS용, 건식 가공
- AlCrN: 내열성 우수, 고속/난삭재
- DLC: 알루미늄/비철용, 낮은 마찰
- 무코팅: 비철 전용, 날카로운 인선

## 가공 종류
- 황삭: 높은 이송, 깊은 절입, 4~6날
- 정삭: 낮은 이송, 면조도 우선, 2~4날
- 슬롯: 100% 물림, 칩 배출 중요
- 측면: 진동 주의

${sessionContext}
${formContext}
${webContext}

═══ 응답 규칙 ═══
- 한국어로 자연스럽게 대화
- 간결하게 (2-5문장)
- 절삭공구 무관한 질문: 짧게 답변 후 "절삭공구 관련 질문도 도와드릴 수 있어요" 정도만
- 기술 질문: 구체적 수치와 비교 포함
- "추가 조건을 알려주시면~" 같은 빈 말 금지
- 응답 끝에 JSON이나 특수 포맷 쓰지 말고 순수 자연어로만
- 모든 답변 끝에 근거 출처를 반드시 한 줄로 표기:
  [Reference: YG-1 내부 DB] — 제품 데이터, 후보 수, 스펙 기반 답변
  [Reference: AI 지식 추론] — 가공 기술, 코팅 특성, 소재 지식 기반 답변
  [Reference: 웹 검색] — 외부 웹 검색 결과 기반 답변`

    const userPrompt = `${sessionContext}\n${formContext}${displayedContext}${webContext}\n\n사용자: "${clean}"`

    const raw = await provider.complete(systemPrompt, [
      { role: "user", content: userPrompt }
    ], 800)

    if (raw && raw.trim()) {
      // Generate contextual chips based on question type
      const chips = generateFollowUpChips(clean, candidateCount)
      return { text: raw.trim(), chips }
    }
  } catch (e) {
    console.warn("[recommend] General chat handler failed:", e)
  }

  // Fallback
  return {
    text: "죄송합니다, 잠시 오류가 있었습니다. 절삭공구 관련 질문이나 가공 조건을 말씀해주세요.",
    chips: ["스테인리스 가공", "알루미늄 10mm", "엔드밀 추천", "절삭조건 문의"],
  }
}

// Generate contextual follow-up chips
function generateFollowUpChips(userMessage: string, candidateCount: number): string[] {
  const lower = userMessage.toLowerCase()

  // If asking about coatings
  if (/코팅|tialn|alcrn|dlc/i.test(lower)) {
    return ["코팅별 적합 소재", "무코팅 vs DLC", "소재별 추천 코팅", "제품 추천"]
  }
  // If asking about materials
  if (/소재|알루|스테인|주철|티타늄|가공/i.test(lower)) {
    return ["절삭조건 알려줘", "추천 코팅은?", "주의사항 더 알려줘", "제품 추천"]
  }
  // If asking about the system
  if (/시스템|점수|매칭|어떻게/i.test(lower)) {
    return ["점수 기준 설명", "소재 태그 뜻", "팩트 체크란?", "제품 추천"]
  }
  // Default
  if (candidateCount > 0) {
    return ["후보 제품 보기", "절삭조건 문의", "코팅 비교", "처음부터 다시"]
  }
  return ["제품 추천", "절삭조건 문의", "코팅 비교", "시리즈 검색"]
}

